class Solution:
    def __init__(self):
        self.root = TrieNode()

    def insert(self, word: str) -> None:
        node = self.root
        for c in word:
            if not hasattr(node, 'children'):
                node.children = {}
            if not c in node.children:
                node.children[c] = TrieNode()
            node = node.children[c]

        # BUGGY CODE: Create a new node for each character instead of updating the existing one
        if not hasattr(node, 'word'):
            node.word = word

    def get_trie(self) -> str:
        def dfs(node, current_word):
            if node.word:
                return current_word + node.word + '\n'
            result = ''
            for c, child in sorted(node.children.items(), key=lambda x: x[0]):
                result += dfs(child, current_word + c)
            return result

        return dfs(self.root, '')

    def main(self):
        T = int(input())
        for _ in range(T):
            word = input().strip()
            self.insert(word)
        print(self.get_trie())

