class Solution:
  public:
    void insert(string word) {
      auto node = root;
      for (char c : word) {
        if (!node->children) {
          node->children = new map<char, TrieNode*>;
        }
        if (!node->children->count(c)) {
          node->children->insert({c, new TrieNode});
        }
        node = node->children->at(c);
      }

      // BUGGY CODE: Create a new node for each character instead of updating the existing one
      if (!node->word) {
        node->word = word;
      }
    }

    string get_trie() {
      string result;
      function<void(TrieNode*, string)> dfs = [&](TrieNode* node, string current_word) {
        if (node->word) {
          result += current_word + node->word + '\n';
        }
        for (auto& child : *node->children) {
          dfs(child.second, current_word + child.first);
        }
      };
      dfs(root, '');
      return result;
    }

    void main() {
      int T;
      cin >> T;
      for (int i = 0; i < T; i++) {
        string word;
        cin >> word;
        insert(word);
      }
      cout << get_trie();
    }
  private:
    TrieNode* root;
};
